import { ReactComponent } from '*.svg';
import ExpenseItem from './Components/ExpenseItem';

function App() {
  let item_list = {
    item1 : {
      date: "24-05-2021",
      title: "SleepWell Bed",
      amount: 12499
    },
    item2 : {
      date: "23-05-2021",
      title: "Antidandruff shampoo",
      amount: 349
    },
    item3 : {
      date: "20-05-2021",
      title: "Castor oil",
      amount: 150
    },
    item4 : {
      date: "20-05-2021",
      title: "Badam",
      amount: 750
    }
  }
  return (
    <div className="App">
      <h2>Let's get started!</h2>
      <ExpenseItem date = {item_list[item1[date]]} title = {item_list[item1[title]]} price = {item_list[item1[price]]}></ExpenseItem>
      <ExpenseItem date = {item_list.item2.date} title = {item_list.item2.title} price = {item_list.item2.price}></ExpenseItem>
      <ExpenseItem date = {item_list.item3.date} title = {item_list.item3.title} price = {item_list.item3.price}></ExpenseItem>
      <ExpenseItem date = {item_list.item4.date} title = {item_list.item4.title} price = {item_list.item4.price}></ExpenseItem>
    </div>
  );
}

export default App;
